// Get the current date and time in GMT+8
const now = new Date();

// Convert to ISO string and format to include the date and time
const options = {
    timeZone: 'Asia/Singapore',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false
};

const formatter = new Intl.DateTimeFormat('en-CA', options);
const parts = formatter.formatToParts(now);

// Create a formatted timestamp in 'YYYY-MM-DD hh:mm:ss' format
const formattedDate = `${parts[0].value}-${parts[2].value}-${parts[4].value} ${parts[6].value}:${parts[8].value}:${parts[10].value}`;

// Return the formatted current timestamp in GMT+8
return {
    json: {
        currentTimestamp: formattedDate
    }
};

// Define the timestamps
const completeAt = $input.first().json.data[0].Complete_at;
const followUpAt = $input.first().json.data[0].Follow_up_at;

// Convert the timestamps to Date objects
const completeDate = new Date(completeAt);
const followUpDate = new Date(followUpAt);

// Calculate the difference in milliseconds
const durationInMs = completeDate - followUpDate;

// Convert milliseconds to hours, minutes, and seconds
const totalSeconds = Math.floor(durationInMs / 1000);
const hours = Math.floor(totalSeconds / 3600);
const minutes = Math.floor((totalSeconds % 3600) / 60);
const seconds = totalSeconds % 60;

const output = hours+" hour(s) "+minutes+ " minute(s) "

// Return the duration
return {
    json: {
        duration: {
            output
        }
    }
};

